// Extraer datos del mensaje entrante de Evolution API
const body = $input.first().json.body || $input.first().json;
const data = body.data || body;

// Ignorar mensajes propios
if (data?.key?.fromMe === true) {
  return [{ json: { ignore: true } }];
}

// Extraer phone
const remoteJid = data?.key?.remoteJid || '';
const phone = remoteJid.split('@')[0];

// Extraer texto
const msg = data?.message || {};
const text = (msg?.conversation || msg?.extendedTextMessage?.text || '').trim();

// Extraer nombre
const pushName = data?.pushName || '';

// Extraer evento
const event = body.event || data?.event || 'messages.upsert';

if (!phone || !text) {
  return [{ json: { ignore: true } }];
}

return [{ json: { phone, text, pushName, event, ignore: false } }];

// Gestión de sesiones usando Static Data de n8n
// Cuando migres a PostgreSQL, reemplaza este nodo por una query SELECT

const phone = $input.first().json.phone;
const text = $input.first().json.text;
const pushName = $input.first().json.pushName;

// Obtener static data (persiste entre ejecuciones)
const staticData = $getWorkflowStaticData('global');

// Inicializar storage si no existe
if (!staticData.sessions) {
  staticData.sessions = {};
}

// Limpiar sesiones expiradas (más de 15 minutos)
const now = Date.now();
for (const p of Object.keys(staticData.sessions)) {
  const session = staticData.sessions[p];
  if (session.lastInteraction && (now - session.lastInteraction) > 15 * 60 * 1000) {
    delete staticData.sessions[p];
  }
}

// Obtener sesión actual o crear nueva
let session = staticData.sessions[phone] || { state: 'START', data: {} };
session.lastInteraction = now;

// Comandos globales
const textLower = text.toLowerCase();
if (textLower === 'salir' || textLower === 'cancelar') {
  delete staticData.sessions[phone];
  return [{ json: { 
    phone, text, pushName,
    state: 'COMMAND_EXIT',
    sessionData: {},
    command: 'exit'
  }}];
}

if (textLower === 'retroceder' && session.state !== 'START') {
  const history = session.data.history || [];
  if (history.length > 1) {
    history.pop();
    session.state = history[history.length - 1];
    session.data.history = history;
  }
}

// Guardar sesión actualizada
staticData.sessions[phone] = session;

return [{ json: {
  phone,
  text,
  textLower,
  pushName,
  state: session.state,
  sessionData: session.data
}}];

// Estado START: Bienvenida y solicitar tipo de documento
const phone = $input.first().json.phone;
const pushName = $input.first().json.pushName;

const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};

// Cargar tipos de documento desde LOLCLI (hardcoded del Python bot)
const docTypes = [
  { tidcod: '01', tiddes: 'DNI' },
  { tidcod: '02', tiddes: 'Carné de Extranjería' },
  { tidcod: '03', tiddes: 'Pasaporte' },
  { tidcod: '04', tiddes: 'Otro' }
];

let menu = '👋 ¡Hola' + (pushName ? ', ' + pushName : '') + '! Bienvenido/a a *LOLIMSA*.\n\n';
menu += 'Soy tu asistente virtual y estoy aquí para ayudarte a agendar tu cita médica. 😊\n\n';
menu += '📋 Para comenzar, ¿cuál es tu tipo de documento de identidad?\n\n';
docTypes.forEach((doc, i) => {
  menu += `*${i+1}.* ${doc.tiddes}\n`;
});
menu += '\n_Escribe el número de tu elección._';

// Actualizar sesión
staticData.sessions[phone] = {
  state: 'AWAITING_DOC_TYPE',
  data: {
    history: ['START', 'AWAITING_DOC_TYPE'],
    docTypeOptions: docTypes
  },
  lastInteraction: Date.now()
};

return [{ json: { phone, reply: menu } }];

// Estado AWAITING_DOC_TYPE: Procesar elección de tipo de documento
const { phone, text, sessionData } = $input.first().json;
const staticData = $getWorkflowStaticData('global');

const docTypes = sessionData.docTypeOptions || [
  { tidcod: '01', tiddes: 'DNI' },
  { tidcod: '02', tiddes: 'Carné de Extranjería' },
  { tidcod: '03', tiddes: 'Pasaporte' },
  { tidcod: '04', tiddes: 'Otro' }
];

// Procesar elección
let selected = null;
const num = parseInt(text);
if (!isNaN(num) && num >= 1 && num <= docTypes.length) {
  selected = docTypes[num - 1];
} else {
  // Buscar por nombre
  const textLow = text.toLowerCase();
  selected = docTypes.find(d => d.tiddes.toLowerCase().includes(textLow));
}

if (!selected) {
  return [{ json: { 
    phone, 
    reply: '❓ No reconocí tu elección. Por favor, escribe el *número* correspondiente a tu tipo de documento.'
  }}];
}

// Actualizar sesión
staticData.sessions[phone] = {
  state: 'AWAITING_DOC_NUMBER',
  data: {
    ...sessionData,
    tidcod: selected.tidcod,
    tiddes: selected.tiddes,
    history: [...(sessionData.history || []), 'AWAITING_DOC_NUMBER']
  },
  lastInteraction: Date.now()
};

return [{ json: { 
  phone,
  reply: `Perfecto, seleccionaste *${selected.tiddes}*. 📄\n\nAhora, por favor ingresa tu número de ${selected.tiddes}.`
}}];

// Estado AWAITING_DOC_NUMBER: Validar documento con LOLCLI
const { phone, text, sessionData } = $input.first().json;
const staticData = $getWorkflowStaticData('global');

const tidcod = sessionData.tidcod;
const docNumber = text.trim();

// Validar DNI
if (tidcod === '01' && (!/^\d{8}$/.test(docNumber))) {
  return [{ json: {
    phone,
    reply: '⚠️ El DNI debe tener exactamente *8 dígitos numéricos*.\n\n¿Puedes verificarlo e intentarlo de nuevo? 🙏',
    nextStep: null
  }}];
}

// Guardar doc number y pasar a validación
staticData.sessions[phone].data.pacdoc = docNumber;
staticData.sessions[phone].data.history = [...(sessionData.history || []), 'AWAITING_DOC_NUMBER'];

return [{ json: {
  phone,
  pacdoc: docNumber,
  tidcod,
  sessionData: staticData.sessions[phone].data,
  reply_pending: true
}}];

// Procesar respuesta de ValidarPaciente
const response = $input.first().json;
const staticData = $getWorkflowStaticData('global');

// Obtener datos del nodo anterior
const sessionNode = $('AWAITING_DOC_NUMBER').first().json;
const phone = sessionNode.phone;
const session = staticData.sessions[phone];
const sessionData = session.data;

const pacientes = response.paciente || [];

if (pacientes.length > 0) {
  // Paciente existente
  const paciente = pacientes[0];
  session.data.pachis = paciente.pachis;
  session.data.paciente_nombre = paciente.pacpmn;
  session.data.pacdir = paciente.pacdir || '';
  session.state = 'AWAITING_ESTABLISHMENT';
  session.data.history = [...(sessionData.history || []), 'AWAITING_ESTABLISHMENT'];
  staticData.sessions[phone] = session;

  return [{ json: {
    phone,
    patientFound: true,
    patientName: paciente.pacpmn,
    sessionData: session.data,
    nextState: 'AWAITING_ESTABLISHMENT'
  }}];
} else {
  // Paciente nuevo
  session.state = 'AWAITING_NEW_PATIENT';
  session.data.isNewPatient = true;
  staticData.sessions[phone] = session;

  return [{ json: {
    phone,
    patientFound: false,
    sessionData: session.data,
    nextState: 'AWAITING_NEW_PATIENT'
  }}];
}

// Formatear menú de establecimientos
const response = $input.first().json;
const staticData = $getWorkflowStaticData('global');

// Obtener phone desde el nodo de proceso de paciente
const processNode = $('Procesar Paciente').first().json;
const phone = processNode.phone;
const patientName = processNode.patientName;
const session = staticData.sessions[phone];

const establecimientos = response.establecimientos || [];

if (establecimientos.length === 0) {
  return [{ json: {
    phone,
    reply: '😔 Lo sentimos, no hay sedes disponibles en este momento. Por favor, intenta más tarde o llámanos directamente.'
  }}];
}

// Formatear menú
let menu = `¡Hola de nuevo, *${patientName}*! 😊\n\n`;
menu += '🏥 ¿En cuál de nuestras sedes te gustaría atenderte?\n\n';
establecimientos.forEach((est, i) => {
  menu += `*${i+1}.* ${est.sisent}\n`;
});
menu += '\n_Escribe el número o el nombre de tu elección._\n_También puedes escribir *retroceder* o *salir*._';

// Actualizar sesión
session.data.establishmentOptions = establecimientos;
session.state = 'AWAITING_ESTABLISHMENT';
staticData.sessions[phone] = session;

return [{ json: { phone, reply: menu } }];

// Estado AWAITING_ESTABLISHMENT
const { phone, text, sessionData } = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const session = staticData.sessions[phone];

const options = sessionData.establishmentOptions || [];

// Procesar elección
let selected = null;
const num = parseInt(text);
if (!isNaN(num) && num >= 1 && num <= options.length) {
  selected = options[num - 1];
} else {
  const textLow = text.toLowerCase();
  selected = options.find(o => o.sisent.toLowerCase().includes(textLow));
}

if (!selected) {
  return [{ json: {
    phone,
    reply: '❓ No reconocí tu elección. Por favor, escribe el *número* de la sede que prefieres.'
  }}];
}

// Actualizar sesión
session.data.siscod = selected.siscod;
session.data.establishment_name = selected.sisent;
session.state = 'AWAITING_SPECIALTY';
session.data.history = [...(sessionData.history || []), 'AWAITING_SPECIALTY'];
staticData.sessions[phone] = session;

return [{ json: {
  phone,
  siscod: selected.siscod,
  establishmentName: selected.sisent,
  sessionData: session.data,
  needsSpecialties: true
}}];

// Formatear menú de especialidades
const response = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const estNode = $('AWAITING_ESTABLISHMENT').first().json;
const phone = estNode.phone;
const session = staticData.sessions[phone];

const servicios = response.servicios || [];

let menu = `🏥 *${session.data.establishment_name}*\n\n`;
menu += '🩺 ¿Para qué especialidad necesitas la cita?\n\n';
servicios.forEach((s, i) => {
  menu += `*${i+1}.* ${s.serdes}\n`;
});
menu += '\n_Escribe el número o nombre de la especialidad._';

session.data.specialtyOptions = servicios;
staticData.sessions[phone] = session;

return [{ json: { phone, reply: menu } }];

// Estado AWAITING_SPECIALTY
const { phone, text, sessionData } = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const session = staticData.sessions[phone];

const options = sessionData.specialtyOptions || [];

let selected = null;
const num = parseInt(text);
if (!isNaN(num) && num >= 1 && num <= options.length) {
  selected = options[num - 1];
} else {
  selected = options.find(o => o.serdes.toLowerCase().includes(text.toLowerCase()));
}

if (!selected) {
  return [{ json: {
    phone,
    reply: '❓ No reconocí esa especialidad. Por favor, escribe el número de tu elección.'
  }}];
}

session.data.sercod = selected.sercod;
session.data.sernam = selected.serdes;
session.state = 'AWAITING_DOCTOR';
session.data.history = [...(sessionData.history || []), 'AWAITING_DOCTOR'];
staticData.sessions[phone] = session;

return [{ json: {
  phone,
  siscod: sessionData.siscod,
  sercod: selected.sercod,
  specialtyName: selected.serdes,
  sessionData: session.data
}}];

// Formatear menú de médicos
const response = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const specNode = $('AWAITING_SPECIALTY').first().json;
const phone = specNode.phone;
const session = staticData.sessions[phone];

const medicos = response.medicos || [];

if (medicos.length === 0) {
  session.state = 'AWAITING_SPECIALTY';
  staticData.sessions[phone] = session;
  return [{ json: {
    phone,
    reply: `😔 Lo sentimos, no hay médicos disponibles para *${specNode.specialtyName}* en esta sede.\n\nEscribe *retroceder* para elegir otra especialidad.`
  }}];
}

let menu = `👨‍⚕️ Médicos disponibles para *${specNode.specialtyName}*:\n\n`;
medicos.forEach((m, i) => {
  menu += `*${i+1}.* Dr(a). ${m.mednam}\n`;
});
menu += '\n_Escribe el número del médico de tu preferencia._';

session.data.doctorOptions = medicos;
staticData.sessions[phone] = session;

return [{ json: { phone, reply: menu } }];

// Estado AWAITING_DOCTOR
const { phone, text, sessionData } = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const session = staticData.sessions[phone];

const options = sessionData.doctorOptions || [];

let selected = null;
const num = parseInt(text);
if (!isNaN(num) && num >= 1 && num <= options.length) {
  selected = options[num - 1];
} else {
  selected = options.find(o => o.mednam.toLowerCase().includes(text.toLowerCase()));
}

if (!selected) {
  return [{ json: {
    phone,
    reply: '❓ No encontré ese médico. Por favor, elige uno de la lista con su número.'
  }}];
}

session.data.medcod = selected.medcod;
session.data.mednam = selected.mednam;
session.state = 'AWAITING_AVAILABLE_DATE';
session.data.history = [...(sessionData.history || []), 'AWAITING_AVAILABLE_DATE'];
staticData.sessions[phone] = session;

const today = new Date();
const todayStr = today.getFullYear().toString() +
  String(today.getMonth()+1).padStart(2,'0') +
  String(today.getDate()).padStart(2,'0');

return [{ json: {
  phone,
  siscod: sessionData.siscod,
  sercod: sessionData.sercod,
  medcod: selected.medcod,
  mednam: selected.mednam,
  fecha: todayStr,
  sessionData: session.data
}}];

// Formatear fechas disponibles
const response = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const docNode = $('AWAITING_DOCTOR').first().json;
const phone = docNode.phone;
const session = staticData.sessions[phone];

const cupos = response.cupos || [];

if (cupos.length === 0) {
  session.state = 'AWAITING_DOCTOR';
  staticData.sessions[phone] = session;
  return [{ json: {
    phone,
    reply: `😔 El Dr(a). *${docNode.mednam}* no tiene fechas disponibles por el momento.\n\nEscribe *retroceder* para elegir otro médico.`
  }}];
}

const days = ['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'];
const months = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

let menu = `📅 Fechas disponibles con *Dr(a). ${docNode.mednam}*:\n\n`;
cupos.forEach((c, i) => {
  const dateStr = c.citdat;
  const year = parseInt(dateStr.substring(0,4));
  const month = parseInt(dateStr.substring(4,6)) - 1;
  const day = parseInt(dateStr.substring(6,8));
  const dateObj = new Date(year, month, day);
  const formatted = `${days[dateObj.getDay()]}, ${day} de ${months[month]}`;
  menu += `*${i+1}.* ${formatted}\n`;
});
menu += '\n_Elige la fecha que más te convenga._';

session.data.dateOptions = cupos;
staticData.sessions[phone] = session;

return [{ json: { phone, reply: menu } }];

// Estado AWAITING_AVAILABLE_DATE
const { phone, text, sessionData } = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const session = staticData.sessions[phone];

const options = sessionData.dateOptions || [];

const num = parseInt(text);
if (isNaN(num) || num < 1 || num > options.length) {
  return [{ json: {
    phone,
    reply: '❓ Por favor, escribe solo el *número* de la fecha que prefieres.'
  }}];
}

const selected = options[num - 1];
const dateStr = selected.citdat;
const year = parseInt(dateStr.substring(0,4));
const month = parseInt(dateStr.substring(4,6)) - 1;
const day = parseInt(dateStr.substring(6,8));
const dateObj = new Date(year, month, day);
const days = ['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'];
const months = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const dateFormatted = `${days[dateObj.getDay()]}, ${day} de ${months[month]}`;

session.data.fecha_api = selected.citdat;
session.data.fecha_user = dateFormatted;
session.state = 'AWAITING_TIME';
session.data.history = [...(sessionData.history || []), 'AWAITING_TIME'];
staticData.sessions[phone] = session;

return [{ json: {
  phone,
  siscod: sessionData.siscod,
  sercod: sessionData.sercod,
  medcod: sessionData.medcod,
  fecha_api: selected.citdat,
  fecha_user: dateFormatted,
  sessionData: session.data
}}];

// Formatear horarios disponibles
const response = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const dateNode = $('AWAITING_AVAILABLE_DATE').first().json;
const phone = dateNode.phone;
const session = staticData.sessions[phone];

const horarios = response.horarios || [];

if (horarios.length === 0) {
  session.state = 'AWAITING_AVAILABLE_DATE';
  staticData.sessions[phone] = session;
  return [{ json: {
    phone,
    reply: `😔 No hay horarios disponibles para *${dateNode.fecha_user}*.\n\nEscribe *retroceder* para elegir otra fecha.`
  }}];
}

let menu = `⏰ Horarios disponibles para el *${dateNode.fecha_user}*:\n\n`;
horarios.forEach((h, i) => {
  const timeStr = h.hora;
  const hours = parseInt(timeStr.substring(0,2));
  const mins = timeStr.substring(2,4);
  const ampm = hours >= 12 ? 'PM' : 'AM';
  const hours12 = hours % 12 || 12;
  menu += `*${i+1}.* ${hours12}:${mins} ${ampm}\n`;
});
menu += '\n_¡Ya casi terminamos! Elige tu hora preferida._';

session.data.timeOptions = horarios;
staticData.sessions[phone] = session;

return [{ json: { phone, reply: menu } }];

// Estado AWAITING_TIME
const { phone, text, sessionData } = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const session = staticData.sessions[phone];

const options = sessionData.timeOptions || [];
const num = parseInt(text);

if (isNaN(num) || num < 1 || num > options.length) {
  return [{ json: {
    phone,
    reply: '⏰ Por favor, escribe solo el *número* del horario que prefieres.'
  }}];
}

const selected = options[num - 1];
const timeStr = selected.hora;
const hours = parseInt(timeStr.substring(0,2));
const mins = timeStr.substring(2,4);
const ampm = hours >= 12 ? 'PM' : 'AM';
const hours12 = hours % 12 || 12;
const timeFormatted = `${hours12}:${mins} ${ampm}`;

session.data.hora_api = selected.hora;
session.data.hora_user = timeFormatted;
session.state = 'AWAITING_APPOINTMENT_TYPE';
session.data.history = [...(sessionData.history || []), 'AWAITING_APPOINTMENT_TYPE'];
staticData.sessions[phone] = session;

return [{ json: {
  phone,
  hora_user: timeFormatted,
  sessionData: session.data,
  reply: `✅ Anotado, a las *${timeFormatted}*.\n\n¿La consulta será *Presencial* o *Virtual*?\n\n*1.* 🏥 Presencial\n*2.* 💻 Virtual`
}}];

// Estado AWAITING_APPOINTMENT_TYPE
const { phone, text, sessionData } = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const session = staticData.sessions[phone];

const textLow = text.toLowerCase();
let cittip = null;
let cittipName = null;

if (text === '1' || textLow.includes('presencial')) {
  cittip = 'P'; cittipName = 'Presencial';
} else if (text === '2' || textLow.includes('virtual')) {
  cittip = 'V'; cittipName = 'Virtual';
}

if (!cittip) {
  return [{ json: {
    phone,
    reply: '❓ Por favor, escribe *1* para Presencial o *2* para Virtual.'
  }}];
}

session.data.cittip = cittip;
session.data.cittip_name = cittipName;
session.state = 'AWAITING_CONFIRMATION';
session.data.history = [...(sessionData.history || []), 'AWAITING_CONFIRMATION'];
staticData.sessions[phone] = session;

// Mostrar resumen
const d = session.data;
const summary = `✨ *Resumen de tu cita:*\n\n` +
  `🏥 *Sede:* ${d.establishment_name}\n` +
  `🩺 *Especialidad:* ${d.sernam}\n` +
  `👨‍⚕️ *Médico:* Dr(a). ${d.mednam}\n` +
  `🗓️ *Fecha:* ${d.fecha_user}\n` +
  `⏰ *Hora:* ${d.hora_user}\n` +
  `📍 *Modalidad:* ${cittipName}\n\n` +
  `¿Todo está correcto? Escribe *Sí* para confirmar o *retroceder* para corregir algo.`;

return [{ json: { phone, reply: summary } }];

// Estado AWAITING_CONFIRMATION
const { phone, text, sessionData } = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const session = staticData.sessions[phone];

const textLow = text.toLowerCase();

if (!['sí', 'si', 'yes', 'confirmar', 'confirmo'].includes(textLow)) {
  return [{ json: {
    phone,
    reply: '🤔 Escribe *Sí* para confirmar tu cita, *retroceder* para corregir algo, o *salir* para cancelar.'
  }}];
}

// Proceder a registrar la cita
session.state = 'PROCESSING_BOOKING';
staticData.sessions[phone] = session;

const d = session.data;
const fecha_api = d.fecha_api;
const hora_api = d.hora_api;
const year = fecha_api.substring(0,4);
const month = fecha_api.substring(4,6);
const day = fecha_api.substring(6,8);
const hours = hora_api.substring(0,2);
const mins = hora_api.substring(2,4);
const fecref = `${day}-${month}-${year} ${hours}:${mins}`;

return [{ json: {
  phone,
  confirmed: true,
  fecref,
  siscod: parseInt(d.siscod),
  medcod: d.medcod,
  sercod: d.sercod,
  pachis: d.pachis,
  cittip: d.cittip,
  sessionData: session.data
}}];

// Procesar resultado del registro de cita
const response = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const confNode = $('AWAITING_CONFIRMATION').first().json;
const phone = confNode.phone;
const session = staticData.sessions[phone];

if (response.status === 'success') {
  session.data.invnum_cita = response.invnum;
  session.data.prfnum_cita = response.prfnum;
  session.state = 'AWAITING_PAYMENT_CONFIRMATION';
  staticData.sessions[phone] = session;

  const d = session.data;
  const successMsg = `🎉 *¡Tu cita ha sido registrada exitosamente!*\n\n` +
    `📋 *N° de Reserva:* ${response.invnum}\n` +
    `👨‍⚕️ *Médico:* Dr(a). ${d.mednam}\n` +
    `🗓️ *Fecha:* ${d.fecha_user}\n` +
    `⏰ *Hora:* ${d.hora_user}\n\n` +
    `💳 En breve recibirás el enlace de pago para completar tu reserva.\n\n` +
    `¡Gracias por elegir *LOLIMSA*! 😊`;

  return [{ json: { phone, reply: successMsg, success: true, invnum: response.invnum } }];
} else {
  const errorMsg = response.message || 'Error desconocido';
  delete staticData.sessions[phone];
  return [{ json: {
    phone,
    reply: `😔 Lo sentimos, no pudimos registrar tu cita: *${errorMsg}*\n\nPor favor, escribe *salir* e inténtalo de nuevo o llámanos directamente.`,
    success: false
  }}];
}

